    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    let maxProfit = originalProfit;
    const halfK = k / 2;

    // Precompute the prefix sum of (strategy[i] * prices[i])
    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + strategy[i] * prices[i];
    }

    // Precompute the sum of (0 * prices[i]) for the first half and (1 * prices[i]) for the second half
    // For a window starting at i, the modified part is [i, i + k - 1]
    // First half: [i, i + halfK - 1] -> set to 0
    // Second half: [i + halfK, i + k - 1] -> set to 1
    // The profit change is:
    // (sum of 0 * prices[m] for m in [i, i + halfK - 1] - sum of original strategy[m] * prices[m] for same m)
    // + (sum of 1 * prices[m] for m in [i + halfK, i + k - 1] - sum of original strategy[m] * prices[m] for same m)
    // Which simplifies to:
    // -sum of original strategy[m] * prices[m] for m in [i, i + halfK - 1]
    // + sum of (1 - strategy[m]) * prices[m] for m in [i + halfK, i + k - 1]

    // Precompute the sum of prices in the second half of the window (sum of prices[m] where m is in [i + halfK, i + k - 1])
    // And the sum of original strategy[m] * prices[m] in the first and second halves
    // We can use sliding window to compute these sums efficiently

    // Compute sum of original strategy[m] * prices[m] in first half (sumOrigFirst)
    // Compute sum of (1 - strategy[m]) * prices[m] in second half (sumGainSecond)
    // The total delta is sumGainSecond - sumOrigFirst

    let sumOrigFirst = 0;
    let sumGainSecond = 0;

    // Initialize the first window [0, k-1]
    for (let i = 0; i < halfK; i++) {
        sumOrigFirst += strategy[i] * prices[i];
    }
    for (let i = halfK; i < k; i++) {
        sumGainSecond += (1 - strategy[i]) * prices[i];
    }

    let delta = sumGainSecond - sumOrigFirst;
    maxProfit = Math.max(maxProfit, originalProfit + delta);

    // Slide the window across the array
    for (let i = 1; i <= n - k; i++) {
        // Remove the leftmost element of the previous first half
        sumOrigFirst -= strategy[i - 1] * prices[i - 1];
        // Add the new element to the first half
        sumOrigFirst += strategy[i + halfK - 1] * prices[i + halfK - 1];

        // Remove the leftmost element of the previous second half
        sumGainSecond -= (1 - strategy[i + halfK - 1]) * prices[i + halfK - 1];
        // Add the new element to the second half
        sumGainSecond += (1 - strategy[i + k - 1]) * prices[i + k - 1];

        delta = sumGainSecond - sumOrigFirst;
        maxProfit = Math.max(maxProfit, originalProfit + delta);
    }

    return maxProfit;
}
