function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    let baseProfit = 0;
    for (let i = 0; i < n; i++) {
        baseProfit += strategy[i] * prices[i];
    }

    const d = k / 2; 

    const prefixP = new Array(n+1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixP[i+1] = prefixP[i] + prices[i];
    }

    const prefixS = new Array(n+1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixS[i+1] = prefixS[i] + strategy[i] * prices[i];
    }

    let maxChange = -Infinity;
    for (let i = 0; i <= n - k; i++) {
        const seg2Start = i + d;
        const seg2End = i + k - 1;
        const A = prefixP[seg2End+1] - prefixP[seg2Start];
        const B = prefixS[i+k] - prefixS[i];
        const change = A - B;

        if (change > maxChange) {
            maxChange = change;
        }
    }

    return baseProfit + Math.max(0, maxChange);
}
